import React from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";



const Galeria=()=>{
    return(
    

    <section className="min-h-[100vh] content-center justify-center py-[25vh]">
        <img src={Wave} className="w-full absolute top-0 left-0"/>
        <div className="text-center m-[5vh]">
            <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">¿Te quedaste con ganas de ver más?</h1>
            <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]"></div>
        </div>
        <div className="w-[50%] mx-auto">
        <MasonryGrid />
      </div>

    </section>

    );
};

export default Galeria;
